@page "/settings"
@rendermode InteractiveServer
@using sv_a1bb4574eb4347048bab699b798c5368.Services

<PageTitle>Settings</PageTitle>

<div class="settings-dashboard">
    <nav class="settings-sidebar">
        <h5 class="px-3 py-2 mb-0 text-muted text-uppercase fw-semibold" style="font-size: 0.75rem; letter-spacing: 0.05em;">Settings</h5>
        @foreach (var section in _sections)
        {
            <button class="settings-nav-item @(section == _activeSection ? "active" : "")"
                    @onclick="() => SetActiveSection(section)">
                <span class="settings-nav-icon">@GetIcon(section)</span>
                @section
            </button>
        }
    </nav>

    <div class="settings-content">
        @if (_activeSection == "Profile")
        {
            <ProfileSection />
        }
        else if (_activeSection == "Notifications")
        {
            <NotificationsSection />
        }
        else if (_activeSection == "Security")
        {
            <SecuritySection />
        }
        else if (_activeSection == "Appearance")
        {
            <AppearanceSection />
        }
    </div>
</div>

@code {
    private readonly string[] _sections = ["Profile", "Notifications", "Security", "Appearance"];
    private string _activeSection = "Profile";

    private void SetActiveSection(string section) => _activeSection = section;

    private static string GetIcon(string section) => section switch
    {
        "Profile" => "👤",
        "Notifications" => "🔔",
        "Security" => "🔒",
        "Appearance" => "🎨",
        _ => "⚙️"
