@using sv_a1bb4574eb4347048bab699b798c5368.Services
@inject ISettingsService SettingsService

<div class="settings-section-header">
    <h3>Profile</h3>
    <p>Manage your personal information</p>
</div>

@if (_loading)
{
    <p class="text-muted">Loading profile…</p>
}
else
{
    <div class="avatar-preview">
        <img src="@_avatarUrl" alt="Avatar" />
        <div>
            <div><strong>@_displayName</strong></div>
            <div class="avatar-url">@_avatarUrl</div>
        </div>
    </div>

    <div class="settings-field">
        <label for="displayName">Display Name</label>
        <input type="text" id="displayName" @bind="_displayName" @bind:event="oninput" />
    </div>

    <div class="settings-field">
        <label for="email">Email</label>
        <input type="email" id="email" @bind="_email" @bind:event="oninput" />
    </div>

    <div class="settings-field">
        <label for="bio">Bio</label>
        <textarea id="bio" @bind="_bio" @bind:event="oninput"></textarea>
    </div>

    <div class="settings-field">
        <label for="avatarUrl">Avatar URL</label>
        <input type="text" id="avatarUrl" @bind="_avatarUrl" @bind:event="oninput" />
    </div>

    <div class="settings-actions">
        <button class="btn-settings btn-settings-primary" @onclick="SaveAsync" disabled="@_saving">
            @(_saving ? "Saving…" : "Save Changes")
        </button>
        <button class="btn-settings btn-settings-secondary" @onclick="Discard" disabled="@_saving">
            Discard Changes
        </button>
    </div>
}

@if (_toastMessage is not null)
{
    <div class="settings-toast">@_toastMessage</div>
}

@code {
    private string _displayName = "";
    private string _email = "";
    private string _bio = "";
    private string _avatarUrl = "";

    private UserProfile? _savedProfile;
    private bool _loading = true;
    private bool _saving;
    private string? _toastMessage;

    protected override async Task OnInitializedAsync()
    {
        _savedProfile = await SettingsService.GetProfileAsync();
        ApplyProfile(_savedProfile);
        _loading = false;
    }

    private void ApplyProfile(UserProfile p)
    {
        _displayName = p.DisplayName;
        _email = p.Email;
        _bio = p.Bio;
        _avatarUrl = p.AvatarUrl;
    }

    private async Task SaveAsync()
    {
        _saving = true;
        var profile = new UserProfile(_displayName, _email, _avatarUrl, _bio);
        await SettingsService.SaveProfileAsync(profile);
        _savedProfile = profile;
        _saving = false;
        await ShowToast("Profile saved successfully!");
    }

    private void Discard()
    {
        if (_savedProfile is not null)
            ApplyProfile(_savedProfile);
    }

    private async Task ShowToast(string message)
    {
        _toastMessage = message;
        StateHasChanged();
        await Task.Delay(3000);
        _toastMessage = null;
    }
}

@using sv_a1bb4574eb4347048bab699b798c5368.Services
@inject ISettingsService SettingsService

<div class="settings-section-header">
    <h3>Notifications</h3>
    <p>Choose how you want to be notified</p>
</div>

@if (_loading)
{
    <p class="text-muted">Loading preferences…</p>
}
else
{
    <div class="toggle-row">
        <div>
            <div class="toggle-label">Email Notifications</div>
            <div class="toggle-description">Receive updates via email</div>
        </div>
        <label class="toggle-switch">
            <input type="checkbox" @bind="_emailNotifications" />
            <span class="toggle-slider"></span>
        </label>
    </div>

    <div class="toggle-row">
        <div>
            <div class="toggle-label">Push Notifications</div>
            <div class="toggle-description">Receive push notifications on your devices</div>
        </div>
        <label class="toggle-switch">
            <input type="checkbox" @bind="_pushNotifications" />
            <span class="toggle-slider"></span>
        </label>
    </div>

    <div class="toggle-row">
        <div>
            <div class="toggle-label">Weekly Digest</div>
            <div class="toggle-description">Get a summary of activity each week</div>
        </div>
        <label class="toggle-switch">
            <input type="checkbox" @bind="_weeklyDigest" />
            <span class="toggle-slider"></span>
        </label>
    </div>

    <h5 class="mt-4 mb-3" style="font-size: 1rem; font-weight: 600;">Muted Channels</h5>
    <div class="channel-list">
        @foreach (var channel in _allChannels)
        {
            var isMuted = _mutedChannels.Contains(channel);
            <div class="channel-item">
                <input type="checkbox" id="ch-@channel"
                       checked="@isMuted"
                       @onchange="e => ToggleMute(channel, (bool)(e.Value ?? false))" />
                <label class="channel-name" for="ch-@channel">#@channel</label>
                @if (isMuted)
                {
                    <span class="channel-muted">Muted</span>
                }
            </div>
        }
    </div>

    <div class="settings-actions">
        <button class="btn-settings btn-settings-primary" @onclick="SaveAsync" disabled="@_saving">
            @(_saving ? "Saving…" : "Save Preferences")
        </button>
    </div>
}

@if (_toastMessage is not null)
{
    <div class="settings-toast">@_toastMessage</div>
}

@code {
    private bool _emailNotifications;
    private bool _pushNotifications;
    private bool _weeklyDigest;
    private List<string> _mutedChannels = [];
    private readonly List<string> _allChannels = MockSettingsService.GetAllChannels();

    private bool _loading = true;
    private bool _saving;
    private string? _toastMessage;

    protected override async Task OnInitializedAsync()
    {
        var prefs = await SettingsService.GetNotificationPrefsAsync();
        _emailNotifications = prefs.EmailNotifications;
        _pushNotifications = prefs.PushNotifications;
        _weeklyDigest = prefs.WeeklyDigest;
        _mutedChannels = [.. prefs.MutedChannels];
        _loading = false;
    }

    private void ToggleMute(string channel, bool mute)
    {
        if (mute && !_mutedChannels.Contains(channel))
            _mutedChannels.Add(channel);
        else if (!mute)
            _mutedChannels.Remove(channel);
    }

    private async Task SaveAsync()
    {
        _saving = true;
        var prefs = new NotificationPrefs(_emailNotifications, _pushNotifications, _weeklyDigest, [.. _mutedChannels]);
        await SettingsService.SaveNotificationPrefsAsync(prefs);
        _saving = false;
        await ShowToast("Notification preferences saved!");
    }

    private async Task ShowToast(string message)
    {
        _toastMessage = message;
        StateHasChanged();
        await Task.Delay(3000);
        _toastMessage = null;
    }
}

@using sv_a1bb4574eb4347048bab699b798c5368.Services
@inject ISettingsService SettingsService

<div class="settings-section-header">
    <h3>Security</h3>
    <p>Manage your account security</p>
</div>

@if (_loading)
{
    <p class="text-muted">Loading security settings…</p>
}
else
{
    <!-- Change Password Panel -->
    <div class="expandable-panel">
        <div class="expandable-header" @onclick="() => _passwordPanelOpen = !_passwordPanelOpen">
            <span style="font-weight: 600;">🔑 Change Password</span>
            <span>@(_passwordPanelOpen ? "▲" : "▼")</span>
        </div>
        @if (_passwordPanelOpen)
        {
            <div class="expandable-body">
                <div class="settings-field">
                    <label for="currentPw">Current Password</label>
                    <input type="password" id="currentPw" @bind="_currentPassword" />
                </div>
                <div class="settings-field">
                    <label for="newPw">New Password</label>
                    <input type="password" id="newPw" @bind="_newPassword" />
                </div>
                <div class="settings-field">
                    <label for="confirmPw">Confirm Password</label>
                    <input type="password" id="confirmPw" @bind="_confirmPassword" />
                </div>
                @if (_passwordError is not null)
                {
                    <div class="text-danger mb-2" style="font-size: 0.85rem;">@_passwordError</div>
                }
                <button class="btn-settings btn-settings-primary" @onclick="ChangePasswordAsync" disabled="@_changingPassword">
                    @(_changingPassword ? "Updating…" : "Update Password")
                </button>
                @if (_settings?.LastPasswordChange is not null)
                {
                    <div class="password-change-info">
                        Last changed: @_settings.LastPasswordChange.Value.ToString("MMM dd, yyyy")
                    </div>
                }
            </div>
        }
    </div>

    <!-- Two-Factor Authentication -->
    <div class="tfa-section">
        <div>
            <div style="font-weight: 600;">Two-Factor Authentication</div>
            <div class="status-indicator mt-1">
                <span class="status-dot @(_twoFactorEnabled ? "enabled" : "disabled")"></span>
                @(_twoFactorEnabled ? "Enabled" : "Disabled")
            </div>
        </div>
        <label class="toggle-switch">
            <input type="checkbox" @bind="_twoFactorEnabled" />
            <span class="toggle-slider"></span>
        </label>
    </div>

    <!-- Active Sessions -->
    <h5 style="font-size: 1rem; font-weight: 600; margin-bottom: 0.75rem;">Active Sessions</h5>
    @if (_settings?.Sessions.Count > 0)
    {
        <div style="overflow-x: auto;">
            <table class="sessions-table">
                <thead>
                    <tr>
                        <th>Device</th>
                        <th>Location</th>
                        <th>Last Active</th>
                        <th></th>
                    </tr>
                </thead>
                <tbody>
                    @foreach (var session in _settings.Sessions)
                    {
                        var isCurrent = session.Id == _settings.Sessions[0].Id;
                        <tr>
                            <td>
                                @session.Device
                                @if (isCurrent)
                                {
                                    <span class="current-badge">Current</span>
                                }
                            </td>
                            <td>@session.Location</td>
                            <td>@FormatLastActive(session.LastActive)</td>
                            <td>
                                @if (!isCurrent)
                                {
                                    <button class="btn-settings btn-settings-outline-danger"
                                            style="font-size: 0.8rem; padding: 0.25rem 0.75rem;"
                                            @onclick="() => PromptRevoke(session)">
                                        Revoke
                                    </button>
                                }
                            </td>
                        </tr>
                    }
                </tbody>
            </table>
        </div>
    }
    else
    {
        <p class="text-muted">No active sessions.</p>
    }
}

<!-- Confirmation Dialog -->
@if (_sessionToRevoke is not null)
{
    <div class="confirm-overlay" @onclick="CancelRevoke">
        <div class="confirm-dialog" @onclick:stopPropagation>
            <h5>Revoke Session</h5>
            <p>Are you sure you want to revoke the session on <strong>@_sessionToRevoke.Device</strong> in @_sessionToRevoke.Location?</p>
            <div class="confirm-actions">
                <button class="btn-settings btn-settings-secondary" @onclick="CancelRevoke">Cancel</button>
                <button class="btn-settings btn-settings-danger" @onclick="ConfirmRevokeAsync" disabled="@_revoking">
                    @(_revoking ? "Revoking…" : "Revoke")
                </button>
            </div>
        </div>
    </div>
}

@if (_toastMessage is not null)
{
    <div class="settings-toast @(_toastIsError ? "error" : "")">@_toastMessage</div>
}

@code {
    private SecuritySettings? _settings;
    private bool _twoFactorEnabled;
    private bool _loading = true;

    // Password change
    private bool _passwordPanelOpen;
    private string _currentPassword = "";
    private string _newPassword = "";
    private string _confirmPassword = "";
    private string? _passwordError;
    private bool _changingPassword;

    // Session revoke
    private ActiveSession? _sessionToRevoke;
    private bool _revoking;

    // Toast
    private string? _toastMessage;
    private bool _toastIsError;

    protected override async Task OnInitializedAsync()
    {
        _settings = await SettingsService.GetSecuritySettingsAsync();
        _twoFactorEnabled = _settings.TwoFactorEnabled;
        _loading = false;
    }

    private async Task ChangePasswordAsync()
    {
        _passwordError = null;

        if (string.IsNullOrWhiteSpace(_currentPassword))
        {
            _passwordError = "Current password is required.";
            return;
        }
        if (string.IsNullOrWhiteSpace(_newPassword) || _newPassword.Length < 8)
        {
            _passwordError = "New password must be at least 8 characters.";
            return;
        }
        if (_newPassword != _confirmPassword)
        {
            _passwordError = "Passwords do not match.";
            return;
        }

        _changingPassword = true;
        await SettingsService.ChangePasswordAsync(_currentPassword, _newPassword);
        _settings = await SettingsService.GetSecuritySettingsAsync();
        _currentPassword = "";
        _newPassword = "";
        _confirmPassword = "";
        _changingPassword = false;
        _passwordPanelOpen = false;
        await ShowToast("Password updated successfully!");
    }

    private void PromptRevoke(ActiveSession session) => _sessionToRevoke = session;
    private void CancelRevoke() => _sessionToRevoke = null;

    private async Task ConfirmRevokeAsync()
    {
        if (_sessionToRevoke is null) return;
        _revoking = true;
        await SettingsService.RevokeSessionAsync(_sessionToRevoke.Id);
        _settings = await SettingsService.GetSecuritySettingsAsync();
        _sessionToRevoke = null;
        _revoking = false;
        await ShowToast("Session revoked.");
    }

    private static string FormatLastActive(DateTime dt)
    {
        var diff = DateTime.UtcNow - dt;
        if (diff.TotalMinutes < 1) return "Just now";
        if (diff.TotalMinutes < 60) return $"{(int)diff.TotalMinutes}m ago";
        if (diff.TotalHours < 24) return $"{(int)diff.TotalHours}h ago";
        return $"{(int)diff.TotalDays}d ago";
    }

    private async Task ShowToast(string message, bool isError = false)
    {
        _toastMessage = message;
        _toastIsError = isError;
        StateHasChanged();
        await Task.Delay(3000);
        _toastMessage = null;
    }
}

@using sv_a1bb4574eb4347048bab699b798c5368.Services
@inject ISettingsService SettingsService

<div class="settings-section-header">
    <h3>Appearance</h3>
    <p>Customize how the app looks and feels</p>
</div>

@if (_loading)
{
    <p class="text-muted">Loading appearance settings…</p>
}
else
{
    <!-- Theme -->
    <div class="settings-field">
        <label>Theme</label>
        <div class="radio-group">
            @foreach (var theme in _themes)
            {
                var id = $"theme-{theme}";
                <div class="radio-option">
                    <input type="radio" name="theme" id="@id" value="@theme"
                           checked="@(_theme == theme)"
                           @onchange="() => _theme = theme" />
                    <label for="@id">@theme</label>
                </div>
            }
        </div>
    </div>

    <!-- Font Size -->
    <div class="settings-field">
        <label>Font Size</label>
        <div class="radio-group">
            @foreach (var size in _fontSizes)
            {
                var id = $"font-{size}";
                <div class="radio-option">
                    <input type="radio" name="fontSize" id="@id" value="@size"
                           checked="@(_fontSize == size)"
                           @onchange="() => _fontSize = size" />
                    <label for="@id">@size</label>
                </div>
            }
        </div>
    </div>

    <!-- Language -->
    <div class="settings-field">
        <label for="language">Language</label>
        <select id="language" @bind="_language">
            @foreach (var lang in _languages)
            {
                <option value="@lang">@lang</option>
            }
        </select>
    </div>

    <!-- Compact Mode -->
    <div class="toggle-row">
        <div>
            <div class="toggle-label">Compact Mode</div>
            <div class="toggle-description">Reduce spacing for a denser layout</div>
        </div>
        <label class="toggle-switch">
            <input type="checkbox" @bind="_compactMode" />
            <span class="toggle-slider"></span>
        </label>
    </div>

    <!-- Live Preview -->
    <div class="appearance-preview">
        <div class="preview-header">Live Preview</div>
        <div class="preview-body theme-@(_theme.ToLowerInvariant()) font-@(_fontSize.ToLowerInvariant()) @(_compactMode ? "compact" : "")">
            <div class="preview-item">
                <span class="preview-sidebar-mock">Home</span>
                <span class="preview-sidebar-mock">Settings</span>
                <span class="preview-sidebar-mock">Profile</span>
            </div>
            <div class="preview-item">
                <strong>Dashboard</strong> — Welcome back! Here's your overview.
            </div>
            <div class="preview-item">
                Theme: <strong>@_theme</strong> · Font: <strong>@_fontSize</strong> · Language: <strong>@_language</strong>
            </div>
            <div class="preview-item">
                This is a preview of how your content will appear with the current settings.
            </div>
        </div>
    </div>

    <div class="settings-actions">
        <button class="btn-settings btn-settings-primary" @onclick="SaveAsync" disabled="@_saving">
            @(_saving ? "Saving…" : "Save")
        </button>
    </div>
}

@if (_toastMessage is not null)
{
    <div class="settings-toast">@_toastMessage</div>
}

@code {
    private string _theme = "Light";
    private string _fontSize = "Medium";
    private string _language = "English";
    private bool _compactMode;

    private readonly string[] _themes = ["Light", "Dark", "System"];
    private readonly string[] _fontSizes = ["Small", "Medium", "Large"];
    private readonly string[] _languages = ["English", "Spanish", "French", "German", "Japanese", "Portuguese", "Chinese"];

    private bool _loading = true;
    private bool _saving;
    private string? _toastMessage;

    protected override async Task OnInitializedAsync()
    {
        var settings = await SettingsService.GetAppearanceAsync();
        _theme = settings.Theme;
        _fontSize = settings.FontSize;
        _language = settings.Language;
        _compactMode = settings.CompactMode;
        _loading = false;
    }

    private async Task SaveAsync()
    {
        _saving = true;
        await SettingsService.SaveAppearanceAsync(new AppearanceSettings(_theme, _fontSize, _language, _compactMode));
        _saving = false;
        await ShowToast("Appearance settings saved!");
    }

    private async Task ShowToast(string message)
