@using sv_a1bb4574eb4347048bab699b798c5368.Services
@inject ISettingsService SettingsService

<div class="settings-section-header">
    <h3>Security</h3>
    <p>Manage your account security</p>
</div>

@if (_loading)
{
    <p class="text-muted">Loading security settings…</p>
}
else
{
    <!-- Change Password Panel -->
    <div class="expandable-panel">
        <div class="expandable-header" @onclick="() => _passwordPanelOpen = !_passwordPanelOpen">
            <span style="font-weight: 600;">🔑 Change Password</span>
            <span>@(_passwordPanelOpen ? "▲" : "▼")</span>
        </div>
        @if (_passwordPanelOpen)
        {
            <div class="expandable-body">
                <div class="settings-field">
                    <label for="currentPw">Current Password</label>
                    <input type="password" id="currentPw" @bind="_currentPassword" />
                </div>
                <div class="settings-field">
                    <label for="newPw">New Password</label>
                    <input type="password" id="newPw" @bind="_newPassword" />
                </div>
                <div class="settings-field">
                    <label for="confirmPw">Confirm Password</label>
                    <input type="password" id="confirmPw" @bind="_confirmPassword" />
                </div>
                @if (_passwordError is not null)
                {
                    <div class="text-danger mb-2" style="font-size: 0.85rem;">@_passwordError</div>
                }
                <button class="btn-settings btn-settings-primary" @onclick="ChangePasswordAsync" disabled="@_changingPassword">
                    @(_changingPassword ? "Updating…" : "Update Password")
                </button>
                @if (_settings?.LastPasswordChange is not null)
                {
                    <div class="password-change-info">
                        Last changed: @_settings.LastPasswordChange.Value.ToString("MMM dd, yyyy")
                    </div>
                }
            </div>
        }
    </div>

    <!-- Two-Factor Authentication -->
    <div class="tfa-section">
        <div>
            <div style="font-weight: 600;">Two-Factor Authentication</div>
            <div class="status-indicator mt-1">
                <span class="status-dot @(_twoFactorEnabled ? "enabled" : "disabled")"></span>
                @(_twoFactorEnabled ? "Enabled" : "Disabled")
            </div>
        </div>
        <label class="toggle-switch">
            <input type="checkbox" @bind="_twoFactorEnabled" />
            <span class="toggle-slider"></span>
        </label>
    </div>

    <!-- Active Sessions -->
    <h5 style="font-size: 1rem; font-weight: 600; margin-bottom: 0.75rem;">Active Sessions</h5>
    @if (_settings?.Sessions.Count > 0)
    {
        <div style="overflow-x: auto;">
            <table class="sessions-table">
                <thead>
                    <tr>
                        <th>Device</th>
                        <th>Location</th>
                        <th>Last Active</th>
                        <th></th>
                    </tr>
                </thead>
                <tbody>
                    @foreach (var session in _settings.Sessions)
                    {
                        var isCurrent = session.Id == _settings.Sessions[0].Id;
                        <tr>
                            <td>
                                @session.Device
                                @if (isCurrent)
                                {
                                    <span class="current-badge">Current</span>
                                }
                            </td>
                            <td>@session.Location</td>
                            <td>@FormatLastActive(session.LastActive)</td>
                            <td>
                                @if (!isCurrent)
                                {
                                    <button class="btn-settings btn-settings-outline-danger"
                                            style="font-size: 0.8rem; padding: 0.25rem 0.75rem;"
                                            @onclick="() => PromptRevoke(session)">
                                        Revoke
                                    </button>
                                }
                            </td>
                        </tr>
                    }
                </tbody>
            </table>
        </div>
    }
    else
    {
        <p class="text-muted">No active sessions.</p>
    }
}

<!-- Confirmation Dialog -->
@if (_sessionToRevoke is not null)
{
    <div class="confirm-overlay" @onclick="CancelRevoke">
        <div class="confirm-dialog" @onclick:stopPropagation>
            <h5>Revoke Session</h5>
            <p>Are you sure you want to revoke the session on <strong>@_sessionToRevoke.Device</strong> in @_sessionToRevoke.Location?</p>
            <div class="confirm-actions">
                <button class="btn-settings btn-settings-secondary" @onclick="CancelRevoke">Cancel</button>
                <button class="btn-settings btn-settings-danger" @onclick="ConfirmRevokeAsync" disabled="@_revoking">
                    @(_revoking ? "Revoking…" : "Revoke")
                </button>
            </div>
        </div>
    </div>
}

@if (_toastMessage is not null)
{
    <div class="settings-toast @(_toastIsError ? "error" : "")">@_toastMessage</div>
}

@code {
    private SecuritySettings? _settings;
    private bool _twoFactorEnabled;
    private bool _loading = true;

    // Password change
    private bool _passwordPanelOpen;
    private string _currentPassword = "";
    private string _newPassword = "";
    private string _confirmPassword = "";
    private string? _passwordError;
    private bool _changingPassword;

    // Session revoke
    private ActiveSession? _sessionToRevoke;
    private bool _revoking;

    // Toast
    private string? _toastMessage;
    private bool _toastIsError;

    protected override async Task OnInitializedAsync()
    {
        _settings = await SettingsService.GetSecuritySettingsAsync();
        _twoFactorEnabled = _settings.TwoFactorEnabled;
        _loading = false;
    }

    private async Task ChangePasswordAsync()
    {
        _passwordError = null;

        if (string.IsNullOrWhiteSpace(_currentPassword))
        {
            _passwordError = "Current password is required.";
            return;
        }
        if (string.IsNullOrWhiteSpace(_newPassword) || _newPassword.Length < 8)
        {
            _passwordError = "New password must be at least 8 characters.";
            return;
        }
        if (_newPassword != _confirmPassword)
        {
            _passwordError = "Passwords do not match.";
            return;
        }

        _changingPassword = true;
        await SettingsService.ChangePasswordAsync(_currentPassword, _newPassword);
        _settings = await SettingsService.GetSecuritySettingsAsync();
        _currentPassword = "";
        _newPassword = "";
        _confirmPassword = "";
        _changingPassword = false;
        _passwordPanelOpen = false;
        await ShowToast("Password updated successfully!");
    }

    private void PromptRevoke(ActiveSession session) => _sessionToRevoke = session;
    private void CancelRevoke() => _sessionToRevoke = null;

    private async Task ConfirmRevokeAsync()
    {
        if (_sessionToRevoke is null) return;
        _revoking = true;
        await SettingsService.RevokeSessionAsync(_sessionToRevoke.Id);
        _settings = await SettingsService.GetSecuritySettingsAsync();
        _sessionToRevoke = null;
        _revoking = false;
        await ShowToast("Session revoked.");
    }

    private static string FormatLastActive(DateTime dt)
    {
        var diff = DateTime.UtcNow - dt;
        if (diff.TotalMinutes < 1) return "Just now";
        if (diff.TotalMinutes < 60) return $"{(int)diff.TotalMinutes}m ago";
        if (diff.TotalHours < 24) return $"{(int)diff.TotalHours}h ago";
        return $"{(int)diff.TotalDays}d ago";
    }

    private async Task ShowToast(string message, bool isError = false)
    {
        _toastMessage = message;
        _toastIsError = isError;
        StateHasChanged();
        await Task.Delay(3000);
        _toastMessage = null;
    }
}

@using sv_a1bb4574eb4347048bab699b798c5368.Services
