    <div class="settings-field">
        <label>Font Size</label>
        <div class="radio-group">
            @foreach (var size in _fontSizes)
            {
                var id = $"font-{size}";
                <div class="radio-option">
                    <input type="radio" name="fontSize" id="@id" value="@size"
                           checked="@(_fontSize == size)"
                           @onchange="() => _fontSize = size" />
                    <label for="@id">@size</label>
                </div>
            }
        </div>
