        <div class="radio-group">
            @foreach (var theme in _themes)
            {
                var id = $"theme-{theme}";
                <div class="radio-option">
                    <input type="radio" name="theme" id="@id" value="@theme"
                           checked="@(_theme == theme)"
                           @onchange="() => _theme = theme" />
                    <label for="@id">@theme</label>
                </div>
            }
        </div>
    </div>

    <!-- Font Size -->
    <div class="settings-field">
        <label>Font Size</label>
        <div class="radio-group">
            @foreach (var size in _fontSizes)
            {
                var id = $"font-{size}";
                <div class="radio-option">
                    <input type="radio" name="fontSize" id="@id" value="@size"
                           checked="@(_fontSize == size)"
                           @onchange="() => _fontSize = size" />
                    <label for="@id">@size</label>
                </div>
            }
        </div>
    </div>

    <!-- Language -->
    <div class="settings-field">
        <label for="language">Language</label>
        <select id="language" @bind="_language">
            @foreach (var lang in _languages)
            {
                <option value="@lang">@lang</option>
            }
        </select>
    </div>

    <!-- Compact Mode -->
    <div class="toggle-row">
        <div>
            <div class="toggle-label">Compact Mode</div>
            <div class="toggle-description">Reduce spacing for a denser layout</div>
        </div>
        <label class="toggle-switch">
            <input type="checkbox" @bind="_compactMode" />
            <span class="toggle-slider"></span>
        </label>
    </div>

    <!-- Live Preview -->
    <div class="appearance-preview">
        <div class="preview-header">Live Preview</div>
        <div class="preview-body theme-@(_theme.ToLowerInvariant()) font-@(_fontSize.ToLowerInvariant()) @(_compactMode ? "compact" : "")">
            <div class="preview-item">
                <span class="preview-sidebar-mock">Home</span>
                <span class="preview-sidebar-mock">Settings</span>
                <span class="preview-sidebar-mock">Profile</span>
            </div>
            <div class="preview-item">
                <strong>Dashboard</strong> — Welcome back! Here's your overview.
            </div>
            <div class="preview-item">
                Theme: <strong>@_theme</strong> · Font: <strong>@_fontSize</strong> · Language: <strong>@_language</strong>
            </div>
            <div class="preview-item">
                This is a preview of how your content will appear with the current settings.
            </div>
        </div>
    </div>

    <div class="settings-actions">
        <button class="btn-settings btn-settings-primary" @onclick="SaveAsync" disabled="@_saving">
            @(_saving ? "Saving…" : "Save")
        </button>
    </div>
}

@if (_toastMessage is not null)
{
    <div class="settings-toast">@_toastMessage</div>
}

@code {
    private string _theme = "Light";
    private string _fontSize = "Medium";
    private string _language = "English";
    private bool _compactMode;

    private readonly string[] _themes = ["Light", "Dark", "System"];
    private readonly string[] _fontSizes = ["Small", "Medium", "Large"];
    private readonly string[] _languages = ["English", "Spanish", "French", "German", "Japanese", "Portuguese", "Chinese"];

    private bool _loading = true;
    private bool _saving;
    private string? _toastMessage;

