        <div>
            <div class="toggle-label">Email Notifications</div>
            <div class="toggle-description">Receive updates via email</div>
        </div>
        <label class="toggle-switch">
            <input type="checkbox" @bind="_emailNotifications" />
            <span class="toggle-slider"></span>
        </label>
    </div>

    <div class="toggle-row">
        <div>
            <div class="toggle-label">Push Notifications</div>
            <div class="toggle-description">Receive push notifications on your devices</div>
        </div>
        <label class="toggle-switch">
            <input type="checkbox" @bind="_pushNotifications" />
            <span class="toggle-slider"></span>
        </label>
    </div>

    <div class="toggle-row">
        <div>
            <div class="toggle-label">Weekly Digest</div>
            <div class="toggle-description">Get a summary of activity each week</div>
        </div>
        <label class="toggle-switch">
            <input type="checkbox" @bind="_weeklyDigest" />
            <span class="toggle-slider"></span>
        </label>
    </div>

    <h5 class="mt-4 mb-3" style="font-size: 1rem; font-weight: 600;">Muted Channels</h5>
    <div class="channel-list">
        @foreach (var channel in _allChannels)
        {
            var isMuted = _mutedChannels.Contains(channel);
            <div class="channel-item">
